# Generated by ollama (starcoder2)
# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

pipeline{
    agent{label 'master'}
    
    stages {
        stage('build docker'){
            agent {label "master"}

            steps {
                sh '''
                docker run --rm -u $(id -u):$(id -g) \
                    -v $WORKSPACE:/usr/src/myapp -w /usr/src/myapp/ \
                    maven:3.5-jdk-8 mvn -B --file pom.xml clean install
                
                mkdir /usr/src/myapp/build
                '''
            }
        }

        stage('push to docker'){
            agent {label "master"}

            steps{
                sh 'docker tag webapp:latest registry.domain.com/myrepo/webapp:latest'
                sh 'docker push registry.domain.com/myrepo/webapp:latest'
                sh 'docker rmi registry.domain.com/myrepo/webapp:latest'
            }
        }
    }
}